import { useEffect } from 'react';
import * as Notifications from 'expo-notifications';
import { useAuth } from '../auth/AuthContext';
import { useDeepLink } from '../navigation/DeepLinkContext';
import { pushPayloadUrl, registerForPushNotificationsAsync } from './pushNotifications';

/**
 * Scaffold: register for push when authenticated and route notification taps via deep links.
 * Backend token registration is deferred until an API endpoint exists.
 */
export function usePushNotifications() {
  const { isAuthenticated } = useAuth();
  const { handleIncomingUrl } = useDeepLink();

  useEffect(() => {
    if (!isAuthenticated) return;

    let cancelled = false;

    registerForPushNotificationsAsync().then(({ expoPushToken, reason }) => {
      if (cancelled) return;
      if (expoPushToken) {
        // Future: POST /api/auth/push-token { token, platform }
        console.log('[push] Expo push token registered (local scaffold):', expoPushToken);
      } else if (reason) {
        console.log('[push] Token unavailable:', reason);
      }
    });

    const responseSub = Notifications.addNotificationResponseReceivedListener((response) => {
      const url = pushPayloadUrl(response.notification.request.content.data as Record<string, unknown>);
      if (url) handleIncomingUrl(url);
    });

    return () => {
      cancelled = true;
      responseSub.remove();
    };
  }, [isAuthenticated, handleIncomingUrl]);
}

import React, { useCallback, useEffect, useState } from 'react';
import {
  ActivityIndicator,
  FlatList,
  Pressable,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import { associatePortal } from '../../../adapters/apiClient';
import { theme } from '../../../theme/portalTheme';

const ASSOCIATE_ACCENT = '#7c3aed';

interface CommissionRow {
  id: number | string;
  accrual_date?: string;
  accrual_type?: string;
  invoice_number?: string;
  invoice_txn_id?: number | string;
  amount?: number | string;
  status?: string;
}

interface CommissionsMeta {
  pagination?: { period_total?: number | string };
}

function fmtInr(value: unknown): string {
  return Number(value || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 });
}

export default function AssociateCommissionsScreen() {
  const [rows, setRows] = useState<CommissionRow[]>([]);
  const [meta, setMeta] = useState<CommissionsMeta>({});
  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(true);

  const load = useCallback(() => {
    setError('');
    setLoading(true);
    associatePortal
      .getCommissions({
        dateFrom: from || undefined,
        dateTo: to || undefined,
        perPage: 100,
      })
      .then((r) => {
        setRows(Array.isArray(r.rows) ? (r.rows as CommissionRow[]) : []);
        setMeta((r.meta as CommissionsMeta) || {});
      })
      .catch((e: Error) => setError(e.message || 'Failed to load'))
      .finally(() => setLoading(false));
  }, [from, to]);

  useEffect(() => {
    load();
  }, []);

  const periodTotal = meta.pagination?.period_total;

  function renderItem({ item: r }: { item: CommissionRow }) {
    const invoice = r.invoice_number || (r.invoice_txn_id != null ? String(r.invoice_txn_id) : '—');
    return (
      <View style={styles.card}>
        <View style={styles.cardRow}>
          <Text style={styles.date}>{r.accrual_date || '—'}</Text>
          <Text style={styles.amount}>₹{fmtInr(r.amount)}</Text>
        </View>
        <Text style={styles.meta}>Type: {r.accrual_type || '—'}</Text>
        <Text style={styles.meta}>Invoice: {invoice}</Text>
        <Text style={styles.meta}>Status: {r.status || '—'}</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={styles.filters}>
        <View style={styles.dateField}>
          <Text style={styles.filterLabel}>From</Text>
          <TextInput
            value={from}
            onChangeText={setFrom}
            placeholder="YYYY-MM-DD"
            placeholderTextColor={theme.muted}
            style={styles.input}
            autoCapitalize="none"
          />
        </View>
        <View style={styles.dateField}>
          <Text style={styles.filterLabel}>To</Text>
          <TextInput
            value={to}
            onChangeText={setTo}
            placeholder="YYYY-MM-DD"
            placeholderTextColor={theme.muted}
            style={styles.input}
            autoCapitalize="none"
          />
        </View>
        <Pressable onPress={load} style={styles.applyBtn}>
          <Text style={styles.applyBtnText}>Apply</Text>
        </Pressable>
      </View>

      {periodTotal != null && (
        <Text style={styles.periodTotal}>
          Period total (accrued): ₹{fmtInr(periodTotal)}
        </Text>
      )}

      {error ? <Text style={styles.error}>{error}</Text> : null}

      {loading && rows.length === 0 ? (
        <View style={styles.center}>
          <ActivityIndicator size="large" color={ASSOCIATE_ACCENT} />
        </View>
      ) : (
        <FlatList
          data={rows}
          keyExtractor={(item) => String(item.id)}
          renderItem={renderItem}
          contentContainerStyle={styles.list}
          ListEmptyComponent={
            !loading ? <Text style={styles.empty}>No rows.</Text> : null
          }
        />
      )}
    </View>
  );
}

